sql:
SELECT SUM(sales) AS total_sales
FROM game_region_sales
WHERE region_id = 1;

SELECT AVG(review_rating) AS average_rating
FROM game_user_reviews
WHERE game_id = 123;

SELECT SUM(sales) AS total_sales
FROM game_region_sales
WHERE region_id = (SELECT region_id FROM regions WHERE region_name = 'North America');

SELECT AVG(review_rating) AS average_rating
FROM game_user_reviews
WHERE review_rating > 3;

external_knowledge:
- "Performance" refers to both sales figures and review ratings; 
- "Cumulative sales" implies a running total of sales for each game in every region, showing how sales build up across regions; 
- "Top 5 platforms" indicates the platforms on which the game sells the most, showing the platforms' names and their respective sales figures.

